#include <stdio.h>
#include <stdlib.h>

int main() {
    double *d;

    /* calloc alocira i inicijalizira memoriju na 0 */
    d = (double *)calloc(1, sizeof(double));

    if (d == NULL) {
        printf("Alokacija nije uspjela.\n");
        return 1;
    }

    printf("Unesite realan broj: ");
    scanf("%lf", d);

    /* umanjenje vrijednosti za 1 */
    *d = *d - 1;

    printf("Umanjena vrijednost je: %.2f\n", *d);

    free(d);

    return 0;
}
